import pytest

def validate_age(age):
    """验证年龄：18-60岁"""
    if not isinstance(age, int):
        raise TypeError("年龄必须是整数")
    if age < 18:
        raise ValueError("年龄不能小于18岁")
    if age > 60:
        raise ValueError("年龄不能超过60岁")
    return True

class TestAgeBoundary:
    # 边界值测试
    def test_boundary_below_min(self):
        """下边界-1: 17岁（无效）"""
        with pytest.raises(ValueError):
            validate_age(17)

    def test_boundary_min(self):
        """下边界: 18岁（有效）"""
        assert validate_age(18)

    def test_boundary_above_min(self):
        """下边界+1: 19岁（有效）"""
        assert validate_age(19)

    def test_normal_value(self):
        """正常值: 30岁（有效）"""
        assert validate_age(30)

    def test_boundary_below_max(self):
        """上边界-1: 59岁（有效）"""
        assert validate_age(59)

    def test_boundary_max(self):
        """上边界: 60岁（有效）"""
        assert validate_age(60)

    def test_boundary_above_max(self):
        """上边界+1: 61岁（无效）"""
        with pytest.raises(ValueError):
            validate_age(61)

    # 使用pytest.mark.parametrize参数化
    @pytest.mark.parametrize("age,expected", [
        (17, False),  # 下边界-1
        (18, True),   # 下边界
        (60, True),   # 上边界
        (61, False),  # 上边界+1
    ])
    def test_age_boundaries(self, age, expected):
        if expected:
            assert validate_age(age)
        else:
            with pytest.raises(ValueError):
                validate_age(age)

