import pytest

class UserService:
    def __init__(self):
        self.users = {"admin": "password123"}
        self.locked_users = set()
        self.login_attempts = {}

    def login(self, username, password):
        # 检查账号是否锁定
        if username in self.locked_users:
            raise ValueError("账号已锁定")

        # 检查账号是否存在
        if username not in self.users:
            raise ValueError("账号不存在")

        # 检查密码
        if self.users[username] != password:
            # 记录失败次数
            self.login_attempts[username] = self.login_attempts.get(username, 0) + 1
            if self.login_attempts[username] >= 3:
                self.locked_users.add(username)
                raise ValueError("密码错误次数过多，账号已锁定")
            raise ValueError("密码错误")

        # 登录成功，重置失败次数
        self.login_attempts[username] = 0
        return {"status": "success", "user": username}

@pytest.fixture
def user_service():
    return UserService()

class TestLoginScenarios:
    """登录场景测试"""

    def test_basic_flow_success(self, user_service):
        """基本流：正常登录成功"""
        result = user_service.login("admin", "password123")
        assert result["status"] == "success"

    def test_alternate_user_not_exist(self, user_service):
        """备选流：账号不存在"""
        with pytest.raises(ValueError, match="账号不存在"):
            user_service.login("unknown", "password")

    def test_alternate_wrong_password(self, user_service):
        """备选流：密码错误"""
        with pytest.raises(ValueError, match="密码错误"):
            user_service.login("admin", "wrongpassword")

    def test_alternate_account_locked(self, user_service):
        """备选流：账号锁定（连续3次密码错误）"""
        # 连续输入错误密码3次
        for _ in range(3):
            try:
                user_service.login("admin", "wrong")
            except ValueError:
                pass

        # 第4次尝试登录
        with pytest.raises(ValueError, match="账号已锁定"):
            user_service.login("admin", "password123")

    # 组合场景测试
    @pytest.mark.parametrize("username,password,expected", [
        ("admin", "password123", "success"),      # 正常登录
        ("unknown", "password", "账号不存在"),      # 账号不存在
        ("admin", "wrong", "密码错误"),            # 密码错误
    ])
    def test_login_scenarios(self, user_service, username, password, expected):
        if expected == "success":
            result = user_service.login(username, password)
            assert result["status"] == "success"
        else:
            with pytest.raises(ValueError, match=expected):
                user_service.login(username, password)

